import{_ as s,C as i,o,c as r,ag as n,E as t}from"./chunks/framework.DLWhSH9p.js";const b=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md"}'),l={name:"guide/index.md"};function d(p,e,c,h,g,u){const a=i("SchemeImage");return o(),r("div",null,[e[0]||(e[0]=n('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>CRAFT Studio is a YouTube content creation platform with AI-powered idea generation, script writing, video production, audio, competitive research, and multi-source resource discovery — backed by PostgreSQL, NATS workers, and 14 specialized AI agents.</p><h2 id="what-you-can-do" tabindex="-1">What You Can Do <a class="header-anchor" href="#what-you-can-do" aria-label="Permalink to &quot;What You Can Do&quot;">​</a></h2><ul><li><strong>Generate Ideas</strong> — AI-powered brainstorming with channel personality, or save from YouTube research</li><li><strong>Write Scripts</strong> — AI write, revise, polish with fact-checking and humanization (Claude, Gemini, Ollama)</li><li><strong>Produce Videos</strong> — 65+ Remotion components with an 8-stage pipeline orchestrated by AI agents</li><li><strong>Research Competitors</strong> — YouTube search with outlier detection, channel deep dives, and earnings estimates</li><li><strong>Curate Content</strong> — AI-scored proposals, approval workflows, and episode pipeline tracking</li><li><strong>Produce Audio</strong> — 300+ TTS voices with screenplay-aware parsing, GPU speech synthesis, and voice cloning</li><li><strong>Find Resources</strong> — Search 14 royalty-free sources for video, image, audio, and reference material</li><li><strong>Track Jobs</strong> — Async NATS workers for AI generation, rendering, and downloads with real-time SSE updates</li><li><strong>Go Mobile</strong> — Android companion app with full dashboard parity over your local network</li></ul>',4)),t(a,{name:"top-chrome",alt:"Top chrome — the Flow redesign layout"}),t(a,{name:"ideas-panel",alt:"Ideas Panel"}),t(a,{name:"channel-dive",alt:"Channel Deep Dive"}),e[1]||(e[1]=n(`<h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><p>The Studio is organised around a <strong>top chrome</strong> — a single header bar — rather than a left sidebar. In it:</p><ul><li><strong>Logo · channel pill · peer avatars</strong> on the left</li><li><strong>Stage rail</strong> across the middle (<code>Discover → Ideas → Scripts → Audio → Episodes</code>) — the five primary workflow stages</li><li><strong>⌘K command palette</strong> slot in the middle-right, then <strong>Resources · Settings · Marketplace · Feedback</strong> on the far right</li><li><strong>Avatar menu</strong> top-right (API keys, password change, theme, sign out)</li></ul><p>Channel-scoped actions (Proposals, Jobs, channel Settings) live inside the channel-pill dropdown. See <a href="/guide/command-palette.html">Top chrome &amp; ⌘K</a> for the full tour.</p><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Browser ──&gt; Studio API ──&gt; Studio runtime</span></span>
<span class="line"><span>              |-- AI (Claude Agent SDK + Gemini + Ollama)</span></span>
<span class="line"><span>              |-- 14 AI Agents (research, write, storyboard, composite...)</span></span>
<span class="line"><span>              |-- YouTube research (yt-dlp + Data API)</span></span>
<span class="line"><span>              |-- TTS (Edge TTS, ElevenLabs, OpenAI, OpenedAI Speech)</span></span>
<span class="line"><span>              |-- Background workers (idea, tts, discover, render...)</span></span>
<span class="line"><span>              |-- Role-based multi-tenant access</span></span>
<span class="line"><span>              |-- Feedback → GitHub Issues (AI grooming + worker)</span></span>
<span class="line"><span>              |-- Persistent storage + caching</span></span>
<span class="line"><span>              |-- Remotion Video (65+ components, Chromium render)</span></span>
<span class="line"><span>              \\-- GPU Services (Ollama, ComfyUI, MusicGen)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Mobile App ──&gt; Same Studio API (local network)</span></span></code></pre></div><h2 id="getting-into-the-studio" tabindex="-1">Getting into the Studio <a class="header-anchor" href="#getting-into-the-studio" aria-label="Permalink to &quot;Getting into the Studio&quot;">​</a></h2><p>Once you&#39;re signed in, the top chrome gives you everything:</p><ul><li><strong>Channel pill</strong> on the left — switch channels, or create your first one.</li><li><strong>Stage rail</strong> across the middle — Discover → Ideas → Scripts → Audio → Episodes.</li><li><strong>⌘K</strong> — search and navigate everything without leaving the keyboard.</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Only a Gemini or Claude API key (set in the avatar menu → API keys) is needed to start generating. Most features work without any paid keys at all.</p></div><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="/guide/command-palette.html">Top chrome &amp; ⌘K</a> — the shortest tour of the new layout</li><li><a href="/guide/channels.html">Channels</a> — create your first channel</li><li><a href="/guide/ideas.html">Ideas</a> — start generating content ideas</li></ul>`,12))])}const S=s(l,[["render",d]]);export{b as __pageData,S as default};
